138	function linkifyContent(content: string): (string | JSX.Element)[] {
139	  const urlPattern = /(https?:\/\/[^\s<]+[^\s<.,;:!?"')\]])/g;
140	  const result: (string | JSX.Element)[] = [];
141	  let lastIndex = 0;
142	  let match: RegExpExecArray | null;
143	
144	  while ((match = urlPattern.exec(content)) !== null) {
145	    if (match.index > lastIndex) {
146	      result.push(content.slice(lastIndex, match.index));
147	    }
148	    const url = match[0];
149	    result.push(
150	      <a
151	        key={`link-${match.index}`}
152	        href={url}
153	        target="_blank"
154	        rel="noopener noreferrer"
155	        className="underline font-medium hover:opacity-80 break-all"
156	        onClick={(e) => e.stopPropagation()}
157	      >
158	        {url}
159	      </a>
160	    );
161	    lastIndex = match.index + url.length;
162	  }
163	
164	  if (lastIndex < content.length) {
165	    result.push(content.slice(lastIndex));
166	  }
167	
168	  return result.length > 0 ? result : [content];
169	}
